const rows = $('Get Open Ledger Rows').all().map(i => i.json);
const orders = $input.all().map(i => i.json);
const esc = (s) => s == null ? '' : String(s).replace(/'/g, "''");
const num = (v) => (v === null || v === undefined || v === '' || isNaN(Number(v))) ? 'NULL' : Number(v);
const out = [];
for (let i = 0; i < rows.length; i++) {
  const r = rows[i];
  const o = orders[i] || {};
  const sets = [];
  let action = 'waiting';
  const terminalUnfilled = ['canceled','expired','rejected'].includes(o.status) && !o.filled_at;
  if (terminalUnfilled) {
    sets.push("status = 'busted'");
    action = 'busted';
  } else {
    if (o.filled_avg_price && !r.entry_fill_price) {
      sets.push('entry_fill_price = ' + num(o.filled_avg_price));
      sets.push("entry_fill_time = '" + esc(o.filled_at) + "'::timestamptz");
      action = 'entry_synced';
    }
    const legs = o.legs || [];
    const leg = legs.find(l => l.status === 'filled');
    if (leg && o.filled_avg_price) {
      const t = String(leg.type || '');
      const reason = t.indexOf('trailing') >= 0 ? 'trail' : (t.indexOf('stop') >= 0 ? 'stop' : 'target');
      const intended = reason === 'stop' ? r.intended_stop : (reason === 'target' ? r.intended_target : null);
      sets.push("exit_reason = '" + reason + "'");
      sets.push("exit_order_id = '" + esc(leg.id) + "'");
      sets.push('intended_exit = ' + num(intended));
      sets.push('exit_fill_price = ' + num(leg.filled_avg_price));
      sets.push("exit_fill_time = '" + esc(leg.filled_at) + "'::timestamptz");
      sets.push("status = 'closed'");
      action = 'closed';
    }
  }
  if (sets.length) {
    out.push({ json: { action: action, symbol: r.symbol, strategy: r.strategy, ledger_id: r.id, sql: 'UPDATE public.trade_ledger SET ' + sets.join(', ') + " WHERE id = '" + esc(r.id) + "'::uuid RETURNING id, status, net_pnl, r_multiple" } });
  }
}
if (!out.length) out.push({ json: { action: 'none', symbol: '', strategy: '', ledger_id: '', sql: 'SELECT 1 AS noop' } });
return out;

const built = $('Build Exit Updates').all().map(i => i.json);
const results = $input.all().map(i => i.json);
const esc = (s) => s == null ? '' : String(s).replace(/'/g, "''");
const closed = [];
let busted = 0, entrySynced = 0;
for (let i = 0; i < built.length; i++) {
  const b = built[i];
  const res = results[i] || {};
  if (b.action === 'closed') closed.push({ symbol: b.symbol, strategy: b.strategy, net_pnl: res.net_pnl, r: res.r_multiple });
  if (b.action === 'busted') busted++;
  if (b.action === 'entry_synced') entrySynced++;
}
const summary = 'exit_sync: ' + closed.length + ' closed, ' + entrySynced + ' entry_synced, ' + busted + ' busted';
const raw = JSON.stringify({ closed: closed, busted: busted, entry_synced: entrySynced }).split('$qet$').join('');
const audit_sql = "INSERT INTO public.audit_log (user_id, workflow_name, execution_id, mode, decision, reason, raw) VALUES (NULL, 'qet-h4-exit-sync', '" + esc($execution.id) + "', 'paper', '" + ((closed.length || busted) ? 'executed' : 'skipped') + "', '" + esc(summary) + "', $qet$" + raw + "$qet$::jsonb)";
let text = '[QET H4] ' + summary;
for (const c of closed) { text += '\n' + c.symbol + ' (' + c.strategy + '): net ' + c.net_pnl + ' | R ' + c.r; }
return [{ json: { closed_count: closed.length, busted: busted, text: text, audit_sql: audit_sql } }];
